<?php
namespace App\Models;
use Illuminate\Database\Eloquent\Model;use Illuminate\Database\Eloquent\Relations\BelongsTo;use Illuminate\Database\Eloquent\SoftDeletes;
class Product extends Model{use SoftDeletes;protected $fillable=['category_id','brand_id','name','slug','image','gallery','short_description','description','specifications','price','discount_price','stock','sku','brand','rating','is_featured','is_new','is_best_selling','is_suggested','is_active','sales_count','features','meta_title','meta_description'];protected $casts=['gallery'=>'array','features'=>'array','specifications'=>'array','price'=>'decimal:2','discount_price'=>'decimal:2','rating'=>'decimal:1','is_featured'=>'boolean','is_new'=>'boolean','is_best_selling'=>'boolean','is_suggested'=>'boolean','is_active'=>'boolean'];public function category():BelongsTo{return $this->belongsTo(Category::class);}public function brandModel():BelongsTo{return $this->belongsTo(Brand::class,'brand_id');}public function getFinalPriceAttribute():float{return(float)($this->discount_price?:$this->price);}public function getDiscountPercentAttribute():int{return $this->discount_price&&$this->price>0?(int)round((($this->price-$this->discount_price)/$this->price)*100):0;}}
